def get_disease_info(disease_name: str) -> dict:
    """Look up detailed disease info. Falls back to generic info if not found."""
    if disease_name in DISEASE_INFO:
        return DISEASE_INFO[disease_name]
    
    # Generic fallback
    is_healthy = "healthy" in disease_name.lower()
    if is_healthy:
        plant = disease_name.split(" - ")[0] if " - " in disease_name else disease_name
        return {
            "overview": f"Your {plant} plant appears healthy with no detectable disease symptoms.",
            "causes": ["N/A — Plant is healthy"],
            "symptoms": ["Normal green coloration", "No lesions or abnormal growths", "Healthy shoot and root development"],
            "treatment": ["No treatment required", "Continue regular watering and fertilization", "Monitor monthly for any changes"],
            "prevention": ["Maintain regular inspection", "Ensure good soil drainage and air circulation", "Use balanced fertilization"],
            "impact": ["Healthy plants produce maximum yield and quality", "No economic losses expected"]
        }
    else:
        parts = disease_name.split(" - ")
        plant = parts[0] if parts else disease_name
        condition = parts[1] if len(parts) > 1 else "Unknown disease"
        return {
            "overview": f"{condition} is a disease identified on your {plant} plant based on visual leaf symptoms.",
            "causes": [
                "Fungal, bacterial, or viral pathogen (species varies by condition)",
                "Warm, humid conditions favor most plant diseases",
                "Poor air circulation in dense crop canopies",
                "Water-stressed or nutrient-deficient plants are more susceptible",
                "Infected plant debris or soil as primary inoculum"
            ],
            "symptoms": [
                "Lesions, spots, or discoloration on leaf surfaces",
                "Potential wilting or stunting of plant growth",
                "Possible premature leaf or fruit drop",
                "Visible mold, rust, or powdery growth in some cases",
                "Reduced photosynthetic area leads to lower yield"
            ],
            "treatment": [
                f"Isolate the affected {plant} plant immediately to prevent spread",
                "Remove and dispose of severely infected leaves and branches",
                "Apply appropriate fungicide, bactericide, or miticide depending on pathogen type",
                "Ensure good soil drainage and reduce overhead watering",
                "Consult your local agricultural extension office for specific recommendations"
            ],
            "prevention": [
                "Use certified disease-free planting material",
                "Practice crop rotation every 2–3 years",
                "Maintain good air circulation through proper plant spacing",
                "Water at the base of plants — avoid wetting leaves",
                "Apply balanced fertilization to maintain strong plant immunity"
            ],
            "impact": [
                "Yield reduction of 10–50% depending on severity and timing",
                "Reduced market value of affected produce",
                "Increased input costs for disease management",
                "Risk of spreading to neighboring plants or fields",
                "Multi-season depletion of plant vigor if unmanaged"
            ]
        }
